// Calculate dates needed across all modules
const now = new Date();
const today = now.toISOString().split('T')[0];
const thirtyDaysAgo = new Date(now - 30 * 86400000).toISOString().split('T')[0];
const sevenDaysAgo = new Date(now - 7 * 86400000).toISOString().split('T')[0];
const ninetyDaysAgo = new Date(now - 90 * 86400000).toISOString().split('T')[0];
const unixNow = Math.floor(now.getTime() / 1000);
const unix30d = Math.floor((now - 30 * 86400000) / 1000);

return [{json: {
  today, thirtyDaysAgo, sevenDaysAgo, ninetyDaysAgo,
  unixNow, unix30d,
  timestamp: now.toISOString(),
  scan_id: "MWATCH_" + today.replace(/-/g,"") + "_" + String(now.getHours()).padStart(2,"0") + String(now.getMinutes()).padStart(2,"0")
}}];

// H37-CALC: Dollar Strength Assessment
const observations = $input.all()[0].json.observations;
if (!observations || observations.length < 20) {
  return [{ json: { module: "H37-DXY", status: "INSUFFICIENT_DATA", signal: "NEUTRAL", gate_pass: true, timestamp: new Date().toISOString() }}];
}
const values = observations.filter(o => o.value !== ".").map(o => ({ date: o.date, value: parseFloat(o.value) })).slice(0, 30);
const current = values[0].value;
const prev = values[1].value;
const sma20 = values.slice(0, 20).reduce((sum, v) => sum + v.value, 0) / 20;
const fiveDayAgo = values[4]?.value || values[values.length - 1].value;
const roc5 = ((current - fiveDayAgo) / fiveDayAgo) * 100;
const dailyChange = ((current - prev) / prev) * 100;
let signal = "NEUTRAL", gate_pass = true, urgency = "NONE";
if (current > sma20 && roc5 > 0.5) { signal = "DOLLAR_STRENGTHENING"; gate_pass = false; urgency = roc5 > 1.5 ? "CRITICAL" : "WARNING"; }
else if (current > sma20 && roc5 > 0) { signal = "DOLLAR_ELEVATED"; gate_pass = true; urgency = "MONITOR"; }
else if (current < sma20 && roc5 < -0.5) { signal = "DOLLAR_WEAKENING"; gate_pass = true; urgency = "NONE"; }
return [{ json: { module: "H37-DXY", current_dxy: current, sma20_dxy: Math.round(sma20*100)/100, roc_5day: Math.round(roc5*100)/100, daily_change_pct: Math.round(dailyChange*100)/100, above_sma20: current > sma20, signal, gate_pass, urgency, assessment: "DXY at " + current + " (SMA20: " + Math.round(sma20*100)/100 + "). " + (current > sma20 ? "ABOVE" : "BELOW") + " 20-day average. 5-day momentum: " + (roc5>0?"+":"") + Math.round(roc5*100)/100 + "%. Signal: " + signal, timestamp: new Date().toISOString() }}];

// H38-CALC: Treasury Yield Assessment
const observations = $input.all()[0].json.observations;
if (!observations || observations.length < 10) {
  return [{ json: { module: "H38-YIELD", status: "INSUFFICIENT_DATA", signal: "NEUTRAL", gate_pass: true, timestamp: new Date().toISOString() }}];
}
const values = observations.filter(o => o.value !== ".").map(o => ({ date: o.date, value: parseFloat(o.value) })).slice(0, 30);
const current = values[0].value, prev = values[1]?.value || current;
const fiveDayAgo = values[4]?.value || current;
const velocity5 = current - fiveDayAgo;
const CAUTION = 4.5, DANGER = 5.0, CRIT_VEL = 0.25;
let signal = "NEUTRAL", gate_pass = true, urgency = "NONE";
if (current >= DANGER && velocity5 > 0) { signal = "YIELD_CRITICAL"; gate_pass = false; urgency = "CRITICAL"; }
else if (current >= CAUTION && velocity5 > CRIT_VEL) { signal = "YIELD_SPIKE"; gate_pass = false; urgency = "CRITICAL"; }
else if (current >= CAUTION && velocity5 > 0) { signal = "YIELD_ELEVATED_RISING"; gate_pass = false; urgency = "WARNING"; }
else if (current >= CAUTION) { signal = "YIELD_ELEVATED_STABLE"; urgency = "MONITOR"; }
else if (velocity5 > CRIT_VEL) { signal = "YIELD_RISING_FAST"; urgency = "MONITOR"; }
return [{ json: { module: "H38-YIELD", current_10y: current, prev_10y: prev, velocity_5day_bps: Math.round(velocity5*100), above_caution: current >= CAUTION, above_danger: current >= DANGER, signal, gate_pass, urgency, assessment: "10Y yield at " + current + "%. 5-day change: " + (velocity5>0?"+":"") + Math.round(velocity5*100) + "bps. Signal: " + signal, timestamp: new Date().toISOString() }}];

// H39-CALC: Fund Flow Assessment
const items = $input.all();
const slv = items[0]?.json || {};
const gld = items[1]?.json || {};
function analyzeFlow(data, symbol) {
  if (!data.v || data.v.length < 10) return { symbol, status: "INSUFFICIENT_DATA", signal: "NEUTRAL", liquidation_signal: false, accumulation_signal: false };
  const volumes = data.v, closes = data.c, len = volumes.length;
  const currentVol = volumes[len-1], currentClose = closes[len-1], prevClose = closes[len-2];
  const priceChange = ((currentClose - prevClose) / prevClose) * 100;
  const avgVol = volumes.slice(0, -1).reduce((s, v) => s + v, 0) / (len - 1);
  const volRatio = currentVol / avgVol;
  return { symbol, current_volume: currentVol, avg_volume: Math.round(avgVol), volume_ratio: Math.round(volRatio*100)/100, price_change_pct: Math.round(priceChange*100)/100, liquidation_signal: volRatio > 2.0 && priceChange < -2, accumulation_signal: volRatio > 1.5 && priceChange > 1 };
}
const slvFlow = analyzeFlow(slv, "SLV");
const gldFlow = analyzeFlow(gld, "GLD");
const flows = [slvFlow, gldFlow];
const liqCount = flows.filter(f => f.liquidation_signal).length;
const accCount = flows.filter(f => f.accumulation_signal).length;
let signal = "NEUTRAL", gate_pass = true, urgency = "NONE";
if (liqCount >= 2) { signal = "INSTITUTIONAL_EXIT"; gate_pass = false; urgency = "CRITICAL"; }
else if (liqCount === 1) { signal = "FLOW_WARNING"; urgency = "WARNING"; }
else if (accCount >= 2) { signal = "INSTITUTIONAL_ACCUMULATION"; }
return [{ json: { module: "H39-FLOW", slv: slvFlow, gld: gldFlow, composite_signal: signal, liquidation_count: liqCount, accumulation_count: accCount, gate_pass, urgency, assessment: "Fund flow: " + liqCount + "/2 ETFs showing liquidation. " + accCount + "/2 accumulation. SLV vol ratio: " + slvFlow.volume_ratio + "x. Signal: " + signal, timestamp: new Date().toISOString() }}];

// CORRELATION GATE CHECK — METATRON v10.7
// Evaluates Kill Switch conditions
// NO OVERRIDE. Circuit breaker.
const items = $input.all();
let h37 = null, h38 = null, h39 = null;
for (const item of items) {
  const m = item.json.module;
  if (m === "H37-DXY") h37 = item.json;
  if (m === "H38-YIELD") h38 = item.json;
  if (m === "H39-FLOW") h39 = item.json;
}
// Default to safe if data missing
if (!h37) h37 = { signal: "NEUTRAL", gate_pass: true };
if (!h38) h38 = { signal: "NEUTRAL", gate_pass: true };
if (!h39) h39 = { composite_signal: "NEUTRAL", gate_pass: true };

let kill_switch = false;
let kill_reason = [];

// Condition A: Dollar + Yield convergence
if (h37.signal === "DOLLAR_STRENGTHENING" && ["YIELD_ELEVATED_RISING","YIELD_SPIKE","YIELD_CRITICAL"].includes(h38.signal)) {
  kill_switch = true;
  kill_reason.push("DXY strengthening + yields rising — second-order metals crush in progress");
}
// Condition B: Institutional exit + dollar not weak
if (h39.composite_signal === "INSTITUTIONAL_EXIT" && h37.signal !== "DOLLAR_WEAKENING") {
  kill_switch = true;
  kill_reason.push("Institutional metals exit detected while dollar not weakening");
}
// Condition C: Triple block
if (!h37.gate_pass && !h38.gate_pass && !h39.gate_pass) {
  kill_switch = true;
  kill_reason.push("All three correlation modules blocking — macro fully adverse");
}

return [{ json: {
  gate: "CORRELATION_GATE_CHECK",
  kill_switch,
  kill_reason: kill_reason.join(" | ") || "CLEAR",
  h37_signal: h37.signal,
  h38_signal: h38.signal,
  h39_signal: h39.composite_signal || h39.signal,
  h37_gate: h37.gate_pass,
  h38_gate: h38.gate_pass,
  h39_gate: h39.gate_pass,
  correlation_status: kill_switch ? "ADVERSE" : (!h37.gate_pass || !h38.gate_pass || !h39.gate_pass) ? "WARNING" : "CLEAR",
  embargo_start: kill_switch ? new Date().toISOString() : null,
  embargo_end: kill_switch ? new Date(Date.now() + 48*3600000).toISOString() : null,
  timestamp: new Date().toISOString()
}}];

