// Log kill switch activation for audit trail
const data = $input.all()[0].json;
return [{ json: {
  event: "CORRELATION_KILL_SWITCH",
  fired_at: new Date().toISOString(),
  h37: data.h37_signal,
  h38: data.h38_signal,
  h39: data.h39_signal,
  reason: data.kill_reason,
  embargo_until: data.embargo_end,
  action: "REDUCE_METALS_50PCT_WITHIN_60MIN"
}}];

// HUNTER MASTER MERGE — Combines all H-module outputs
// Includes correlation data from Gate Check
const items = $input.all();
const modules = {};
const errors = [];
for (const item of items) {
  const d = item.json;
  if (d.module) modules[d.module] = d;
  else if (d.gate === "CORRELATION_GATE_CHECK") modules.CORRELATION = d;
  else if (d.error) errors.push(d);
}
const moduleCount = Object.keys(modules).length;
const scan_id = "MWATCH_" + new Date().toISOString().split('T')[0].replace(/-/g,"");
return [{ json: {
  scan_id,
  timestamp: new Date().toISOString(),
  module_count: moduleCount,
  modules,
  errors,
  correlation_status: modules.CORRELATION?.correlation_status || "UNKNOWN",
  data_quality: moduleCount >= 30 ? "HIGH" : moduleCount >= 20 ? "MEDIUM" : "LOW"
}}];

// DATA AGGREGATOR — Formats merged data for Collective analysis
// Output: structured JSON ready for MICHA PASS 1 and CIL
const data = $input.all()[0].json;
return [{ json: {
  type: "MARKET_WATCH_SCAN",
  scan_id: data.scan_id,
  timestamp: data.timestamp,
  module_count: data.module_count,
  data_quality: data.data_quality,
  correlation_status: data.correlation_status,
  summary: {
    intelligence: "H1-H6 data collected",
    technical: "H7-H16 indicators processed",
    flow: "H15-H21 positioning analyzed",
    market_intel: "H22-H29 macro/sector data",
    influence: "H30-H36 political intelligence",
    correlation: "H37-H39 macro correlation: " + data.correlation_status
  },
  full_data: data.modules,
  errors: data.errors,
  ready_for_cil: true
}}];

